// paginatedGet fetches pages and concatenates array results. The headers
// argument carries per-endpoint required headers (e.g. cal-api-version) that
// must be sent on every page request, including the first; pass nil when the
// endpoint has no per-endpoint header overrides.
func paginatedGet(c interface {
	GetWithHeaders(path string, params map[string]string, headers map[string]string) (json.RawMessage, error)
}, path string, params map[string]string, headers map[string]string, fetchAll bool, cursorParam, nextCursorPath, hasMoreField string) (json.RawMessage, error) {
	// Clean zero-value params
	clean := map[string]string{}
	for k, v := range params {
		if v != "" && v != "0" && v != "false" {
			clean[k] = v
		}
	}

	if !fetchAll {
		return c.GetWithHeaders(path, clean, headers)
	}

	// Fetch all pages
	var allItems []json.RawMessage
	page := 0
	for {
		page++
		if humanFriendly {
			fmt.Fprintf(os.Stderr, "fetching page %d...\n", page)
		} else {
			fmt.Fprintf(os.Stderr, `{"event":"page_fetch","page":%d}`+"\n", page)
		}

		data, err := c.GetWithHeaders(path, clean, headers)
		if err != nil {
			return nil, err
		}

		// Try to extract items array
		var items []json.RawMessage
		if json.Unmarshal(data, &items) == nil {
			allItems = append(allItems, items...)
		} else {
			// Response is an object - look for array inside
			var obj map[string]json.RawMessage
			if json.Unmarshal(data, &obj) == nil {
				itemsBefore := len(allItems)
				// Try common data fields
				for _, field := range []string{"data", "items", "results", "messages", "members", "values"} {
					if arr, ok := obj[field]; ok {
						var nested []json.RawMessage
						if json.Unmarshal(arr, &nested) == nil {
							allItems = append(allItems, nested...)
							break
						}
					}
				}
				itemsAdded := len(allItems) - itemsBefore

				// Check for next cursor
				if nextCursorPath != "" {
					if tokenRaw, ok := obj[nextCursorPath]; ok {
						var token string
						if json.Unmarshal(tokenRaw, &token) == nil && token != "" {
							clean[cursorParam] = token
							continue
						}
					}
				}

				// Check has_more
				if hasMoreField != "" {
					if moreRaw, ok := obj[hasMoreField]; ok {
						var more bool
						if json.Unmarshal(moreRaw, &more) == nil && more {
							continue
						}
					}
				}

				if nextOffset, ok := nextOffsetFromEnvelope(obj, clean, itemsAdded); ok {
					clean["offset"] = fmt.Sprintf("%d", nextOffset)
					continue
				}
			}
			// No more pages
			break
		}

		// For direct arrays, can't paginate without cursor
		break
	}

	if humanFriendly {
		fmt.Fprintf(os.Stderr, "fetched %d items across %d pages\n", len(allItems), page)
	} else {
		fmt.Fprintf(os.Stderr, `{"event":"complete","total":%d,"pages":%d}`+"\n", len(allItems), page)
	}
	result, _ := json.Marshal(allItems)
	return json.RawMessage(result), nil
}

func nextOffsetFromEnvelope(obj map[string]json.RawMessage, params map[string]string, itemsAdded int) (int, bool) {
	if itemsAdded <= 0 {
		return 0, false
	}
	paginationRaw, ok := obj["pagination"]
	if !ok {
		if metaRaw, hasMeta := obj["meta"]; hasMeta {
			paginationRaw = metaRaw
		}
	}
	if len(paginationRaw) == 0 {
		return 0, false
	}
	var pagination map[string]json.RawMessage
	if json.Unmarshal(paginationRaw, &pagination) != nil {
		return 0, false
	}
	total, hasTotal := intFromJSONFields(pagination, "total", "total_available", "total_count", "count")
	limit, hasLimit := intFromJSONFields(pagination, "limit", "page_size", "per_page")
	offset, hasOffset := intFromJSONFields(pagination, "offset", "skip")
	if !hasOffset {
		offset, _ = atoiDefault(params["offset"], 0)
	}
	if !hasLimit {
		limit, _ = atoiDefault(params["limit"], itemsAdded)
	}
	if limit <= 0 {
		limit = itemsAdded
	}
	next := offset + limit
	if itemsAdded < limit {
		return 0, false
	}
	if hasTotal && next >= total {
		return 0, false
	}
	return next, true
}

func intFromJSONFields(obj map[string]json.RawMessage, names ...string) (int, bool) {
	for _, name := range names {
		raw, ok := obj[name]
		if !ok {
			continue
		}
		var n int
		if json.Unmarshal(raw, &n) == nil {
			return n, true
		}
		var f float64
		if json.Unmarshal(raw, &f) == nil {
			return int(f), true
		}
		var s string
		if json.Unmarshal(raw, &s) == nil {
			if parsed, err := atoiDefault(s, 0); err == nil {
				return parsed, true
			}
		}
	}
	return 0, false
}

func atoiDefault(s string, fallback int) (int, error) {
	if strings.TrimSpace(s) == "" {
		return fallback, nil
	}
	n, err := strconv.Atoi(strings.TrimSpace(s))
	if err != nil {
		return fallback, err
	}
	return n, nil
}

